        " \"valid\" : { \"$binary\" : \"YXNkZmFz\", \"$type\" : \"80\" },"
        " \"invalid\" : { \"$binary\" : \"invalid\", \"$type\" : \"80\" } }";
    bson_t b;
    bool r;
    char *str;

    // This causes a segmentation fault
    r = bson_init_from_json (&b, json, -1, &error);
    assert (!r);

    bson_destroy (&b);
 }
